def solve(s: String): Array[String] = {
  val segments = Array.ofDim[String](s.length)
  val seen = scala.collection.mutable.Set[String]()
  var currentSegment = ""
  var index = 0
  var segmentIndex = 0

  while (index < s.length) {
    currentSegment += s(index)
    index += 1

    if (seen.contains(currentSegment)) {
      segments(segmentIndex) = currentSegment
      seen.add(currentSegment)
      currentSegment = ""
      segmentIndex += 1
    }
  }

  if (currentSegment.nonEmpty) {
    segments(segmentIndex) = currentSegment
  }

  segments.take(segmentIndex + 1)
}
